  if (aQueryKeysLen !== Object.keys(b.query).length) return false
  for (let j = aQueryKeysLen; j-- !== 0;) {
    if (!Object.prototype.hasOwnProperty.call(b.query, aQueryKeys[j])) return false
  }
  // Only compare the value when shapes are the same
  for (let j = aQueryKeysLen; j-- !== 0;) {
    const queryKey = aQueryKeys[j]
    if (a.query[queryKey] !== b.query[queryKey]) return false;
  }

  for (let i = aKeysLen; i-- !== 0;) {  
    const key = aKeys[i];
    if (key === 'query') continue;

    // It is less likely that shapes of router states are different
